/*============================================Tour de Outback — Main JavaScript============================================*/function initCountdown(){const eventDate=new Date('2026-06-27T07:00:00-07:00').getTime();const daysEl=document.getElementById('countdown-days');const hoursEl=document.getElementById('countdown-hours');const minsEl=document.getElementById('countdown-mins');const secsEl=document.getElementById('countdown-secs');if(!daysEl)return;function update(){const now=new Date().getTime();const diff=eventDate-now;if(diff<=0){daysEl.textContent='0';hoursEl.textContent='0';minsEl.textContent='0';secsEl.textContent='0';return;}daysEl.textContent=Math.floor(diff/(1000*60*60*24));hoursEl.textContent=Math.floor((diff %(1000*60*60*24))/(1000*60*60));minsEl.textContent=Math.floor((diff %(1000*60*60))/(1000*60));secsEl.textContent=Math.floor((diff %(1000*60))/1000);}update();setInterval(update,1000);}function initMobileNav(){const toggle=document.querySelector('.nav-toggle');const links=document.querySelector('.nav-links');if(!toggle||!links)return;toggle.addEventListener('click',()=>{toggle.classList.toggle('active');links.classList.toggle('open');});links.querySelectorAll('a').forEach(link=>{link.addEventListener('click',()=>{toggle.classList.remove('active');links.classList.remove('open');});});}function initNavScroll(){const navbar=document.querySelector('.navbar');if(!navbar)return;window.addEventListener('scroll',()=>{if(window.scrollY>50){navbar.classList.add('scrolled');}else{navbar.classList.remove('scrolled');}});}function initFAQ(){const items=document.querySelectorAll('.faq-item');items.forEach(item=>{const question=item.querySelector('.faq-question');if(!question)return;question.addEventListener('click',()=>{const isOpen=item.classList.contains('open');items.forEach(i=>i.classList.remove('open'));if(!isOpen){item.classList.add('open');}});});}function setActiveNav(){const path=window.location.pathname;const navLinks=document.querySelectorAll('.nav-links a:not(.btn)');navLinks.forEach(link=>{const href=link.getAttribute('href');if((href==='/'&&(path==='/'||path==='/index.html'))||(href!=='/'&&path.startsWith(href.replace(/\/$/,'')))){link.classList.add('active');}});}function initNewsletter(){}function initRegisterTracking(){document.querySelectorAll('a[href*="bikereg.com"]').forEach(link=>{link.addEventListener('click',()=>{if(typeof gtag==='function'){gtag('event','register_click',{event_category:'conversion',event_label:link.textContent.trim(),transport_type:'beacon'});}});});}function initWeather(){var widget=document.getElementById('weather-widget');if(!widget)return;function degToCompass(deg){var dirs=['N','NNE','NE','ENE','E','ESE','SE','SSE','S','SSW','SW','WSW','W','WNW','NW','NNW'];return dirs[Math.round(deg/22.5)% 16];}function renderWeather(icon,temp,windSpeed,windDir){var html='<span class="weather-location">Lake County</span>'+'<span class="weather-bottom"><span class="weather-icon">'+icon+'</span>'+'<span class="weather-temp">'+temp+'°F</span></span>';if(windSpeed!==undefined&&windDir!==undefined){html+='<span class="weather-wind">'+degToCompass(windDir)+' '+windSpeed+' mph</span>';}widget.innerHTML=html;}var cached=sessionStorage.getItem('weatherData');if(cached){var c=JSON.parse(cached);renderWeather(c.icon,c.temp,c.windSpeed,c.windDir);}var weatherCodes={0:'☀️',1:'🌤️',2:'⛅',3:'☁️',45:'🌫️',48:'🌫️',51:'🌦️',53:'🌦️',55:'🌧️',61:'🌦️',63:'🌧️',65:'🌧️',71:'🌨️',73:'❄️',75:'❄️',77:'🌨️',80:'🌦️',81:'🌧️',82:'🌧️',85:'🌨️',86:'🌨️',95:'⛈️',96:'⛈️',99:'⛈️'};fetch('https://api.open-meteo.com/v1/forecast?latitude=42.1888&longitude=-120.3458&current=temperature_2m,weather_code,wind_speed_10m,wind_direction_10m&temperature_unit=fahrenheit&wind_speed_unit=mph&timezone=America/Los_Angeles').then(function(res){return res.json();}).then(function(data){var temp=Math.round(data.current.temperature_2m);var icon=weatherCodes[data.current.weather_code]||'🌡️';var windSpeed=Math.round(data.current.wind_speed_10m);var windDir=data.current.wind_direction_10m;renderWeather(icon,temp,windSpeed,windDir);sessionStorage.setItem('weatherData',JSON.stringify({icon:icon,temp:temp,windSpeed:windSpeed,windDir:windDir,timestamp:Date.now()}));}).catch(function(){if(!cached)widget.innerHTML='';});}document.addEventListener('DOMContentLoaded',()=>{initCountdown();initMobileNav();initNavScroll();initFAQ();setActiveNav();initNewsletter();initRegisterTracking();initWeather();});